import pytest
import yaml
import math
import sys
from pathlib import Path

sys.path.insert(0, str(Path(__file__).parent.parent))

import graph


@pytest.fixture(scope="session")
def fixtures_dir():
    return Path(__file__).parent / "fixtures"


def load_fixture(fixture_path):
    with open(fixture_path) as f:
        return yaml.safe_load(f)


def create_heuristic(heuristic_spec):
    """Create a heuristic function from YAML specification."""
    heuristic_type = heuristic_spec.get("type", "zero")
    coordinates = heuristic_spec.get("coordinates", {})

    if heuristic_type == "zero":
        return lambda v: 0

    elif heuristic_type == "manhattan":
        def manhattan_heuristic(vertex):
            v_elem = vertex.element()
            if v_elem not in coordinates:
                return 0
            return abs(coordinates[v_elem] - coordinates.get("goal", 0))
        return manhattan_heuristic

    elif heuristic_type == "euclidean":
        def euclidean_heuristic(vertex):
            v_elem = vertex.element()
            if v_elem not in coordinates:
                return 0
            v_coord = coordinates[v_elem]
            goal_coord = coordinates.get("goal", [0, 0])
            dx = v_coord[0] - goal_coord[0]
            dy = v_coord[1] - goal_coord[1]
            return math.sqrt(dx * dx + dy * dy)
        return euclidean_heuristic

    else:
        return lambda v: 0


@pytest.fixture(scope="session", params=[
    "simple_path.yaml",
    "grid_graph.yaml",
    "unreachable.yaml"
])
def graph_fixture(request, fixtures_dir):
    """Load a graph fixture and return graph, test cases, and heuristic."""
    fixture_data = load_fixture(fixtures_dir / request.param)

    G, weight_mapping = graph.create_graph(
        fixture_data["edges"],
        is_directed=True
    )

    heuristic = create_heuristic(fixture_data.get("heuristic", {}))

    return {
        "name": fixture_data["name"],
        "graph": G,
        "weight_mapping": weight_mapping,
        "test_cases": fixture_data.get("test_cases", []),
        "heuristic": heuristic,
    }

